                    IconButton(
                      tooltip: 'Add habit',
                      onPressed: () => HabitFormSheet.show(context),
                      icon: Container(
                        width: 40,
                        height: 40,
                        decoration: BoxDecoration(
                          color: AppTheme.deepCharcoal,
                          shape: BoxShape.circle,
                        ),
                        child: const Icon(
                          Icons.add_rounded,
                          color: Colors.white,
                          size: 24,
                        ),
                      ),
                    ),
                    const SizedBox(width: 8),
                    IconButton(
                      tooltip: 'Open profile',
                      onPressed: () {
                        Navigator.of(context).push(
